import{_ as t,o as e,c as r,ae as l}from"./chunks/framework.BeMCGcrk.js";const u=JSON.parse('{"title":"科技股日报 2026年3月20日","description":"","frontmatter":{"title":"科技股日报 2026年3月20日","date":"2026-03-20T00:00:00.000Z","tags":["科技股","阿里巴巴","美团","小米","股市分析"]},"headers":[],"relativePath":"blog/2026-03-20-tech-stocks-daily.md","filePath":"blog/2026-03-20-tech-stocks-daily.md"}'),o={name:"blog/2026-03-20-tech-stocks-daily.md"};function i(h,a,n,s,d,c){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="科技股日报-2026年3月20日" tabindex="-1">科技股日报 2026年3月20日 <a class="header-anchor" href="#科技股日报-2026年3月20日" aria-label="Permalink to &quot;科技股日报 2026年3月20日&quot;">​</a></h1><p>今日科技板块热点：阿里巴巴财报即将发布、美团启动大规模春招、小米新品发布会定档。</p><h2 id="阿里巴巴-baba-us-9988-hk" tabindex="-1">阿里巴巴 (BABA.US / 9988.HK) <a class="header-anchor" href="#阿里巴巴-baba-us-9988-hk" aria-label="Permalink to &quot;阿里巴巴 (BABA.US / 9988.HK)&quot;">​</a></h2><h3 id="财报前瞻" tabindex="-1">财报前瞻 <a class="header-anchor" href="#财报前瞻" aria-label="Permalink to &quot;财报前瞻&quot;">​</a></h3><p>阿里巴巴将于 <strong>3月19日美股盘前</strong> 发布2026财年第三季度（截至2025年12月31日）业绩报告。机构预期：</p><ul><li>营收：2897.3亿元，同比增加3%</li><li>云业务高歌猛进，传统电商增长乏力</li></ul><h3 id="ai布局加速" tabindex="-1">AI布局加速 <a class="header-anchor" href="#ai布局加速" aria-label="Permalink to &quot;AI布局加速&quot;">​</a></h3><ul><li>近期密集发布多款AI大模型</li><li>钉钉发布AI原生工作平台&quot;悟空&quot;</li><li>股价表现：3月17日港股盘中涨超3%，报138.2港元</li></ul><h2 id="美团-3690-hk" tabindex="-1">美团 (3690.HK) <a class="header-anchor" href="#美团-3690-hk" aria-label="Permalink to &quot;美团 (3690.HK)&quot;">​</a></h2><h3 id="_2026春季校招启动" tabindex="-1">2026春季校招启动 <a class="header-anchor" href="#_2026春季校招启动" aria-label="Permalink to &quot;2026春季校招启动&quot;">​</a></h3><p>美团正式宣布启动2026届春季校园招聘：</p><table tabindex="0"><thead><tr><th>类别</th><th>规模</th></tr></thead><tbody><tr><td>2026届补招</td><td>6000人</td></tr><tr><td>2027届转正实习</td><td>3000+人</td></tr></tbody></table><p><strong>亮点：</strong></p><ul><li>大模型等AI技术人才招聘成焦点</li><li>首招&quot;食杂零售管培生&quot;</li><li>覆盖技术、产品、商业分析等100+岗位</li></ul><h2 id="小米-1810-hk" tabindex="-1">小米 (1810.HK) <a class="header-anchor" href="#小米-1810-hk" aria-label="Permalink to &quot;小米 (1810.HK)&quot;">​</a></h2><h3 id="春季新品发布会" tabindex="-1">春季新品发布会 <a class="header-anchor" href="#春季新品发布会" aria-label="Permalink to &quot;春季新品发布会&quot;">​</a></h3><p>小米2026春季新品发布会定档 <strong>3月19日19:00</strong>，新一代SU7将正式上市。</p><h3 id="春招同步启动" tabindex="-1">春招同步启动 <a class="header-anchor" href="#春招同步启动" aria-label="Permalink to &quot;春招同步启动&quot;">​</a></h3><p>小米集团2026届春季校园招聘已于3月9日启动，面向海内外应届毕业生。</p><hr><p><strong>风险提示：</strong> 本文仅供参考，不构成投资建议。</p><p><strong>参考来源：</strong></p><ul><li><a href="https://finance.eastmoney.com/a/202603193677276237.html" target="_blank" rel="noreferrer">阿里财报将于3月19日公布</a></li><li><a href="http://www.aastocks.com/sc/stocks/news/aafn-con/GLH2350910L/latest-news/GLH" target="_blank" rel="noreferrer">阿里AI版图再扩张</a></li><li><a href="https://www.nbd.com.cn/articles/2026-03-04/4278725.html" target="_blank" rel="noreferrer">美团启动2026年春季校招</a></li><li><a href="http://km.bendibao.com/news/2026316/102445.shtm" target="_blank" rel="noreferrer">小米2026春季新品发布会</a></li><li><a href="https://news.qq.com/rain/a/20260309A04DMP00" target="_blank" rel="noreferrer">小米2026届春季校招启动</a></li></ul>',23)])])}const p=t(o,[["render",i]]);export{u as __pageData,p as default};
